using UnityEngine;
using Climbing;

public class RootTeleporter
{
    public static string Run()
    {
        // Find the root player object
        GameObject root = GameObject.Find("Player_New");
        if (root == null) root = GameObject.Find("Player");
        if (root == null) return "Root Player object not found in scene.";

        RaycastHit hit;
        // Raycast from the root's position
        if (Physics.Raycast(root.transform.position + Vector3.up * 2.0f, Vector3.down, out hit, 100f))
        {
            root.transform.position = hit.point + Vector3.up * 0.1f;

            // Also check the child PlayerModel's local position
            Transform pm = root.transform.Find("PlayerModel");
            string localPosInfo = "";
            if (pm != null) {
                pm.localPosition = Vector3.zero;
                localPosInfo = " | Reset PlayerModel localPosition to Zero.";
            }

            return $"Teleported ROOT {root.name} to ground at {hit.point}{localPosInfo}";
        }

        return "No ground found below root player.";
    }
}
